# Skeptic review S52-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'stakeholders', 'metrics', 'baseline_frozen', 'jobs', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["jobs"] != 0 or not record["baseline_frozen"] else "REOPEN_CF1"

valid = {'case_id': 'CASO-PER-052-1A', 'stakeholders': {'privacy', 'relationship', 'ops'}, 'jobs': 3, 'metrics': {'ttr', 'review_precision'}, 'baseline_frozen': True}
invalid = {'case_id': 'CASO-PER-052-1A', 'stakeholders': {'privacy', 'relationship', 'ops'}, 'jobs': 0, 'metrics': {'ttr', 'review_precision'}, 'baseline_frozen': True}
incomplete = {**valid}
incomplete.pop('baseline_frozen', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

